export { DataTableCellText } from "./data-table-cell-text";
export { DataTableCellCode } from "./data-table-cell-code";
export { DataTableCellNumber } from "./data-table-cell-number";
export { DataTableCellBar } from "./data-table-cell-bar";
export { DataTableCellHeatmap } from "./data-table-cell-heatmap";
export { DataTableCellGauge } from "./data-table-cell-gauge";
export { DataTableCellTimestamp } from "./data-table-cell-timestamp";
export { DataTableCellBadge } from "./data-table-cell-badge";
export { DataTableCellBoolean } from "./data-table-cell-boolean";
export { DataTableCellStar } from "./data-table-cell-star";
export { DataTableCellStatusCode } from "./data-table-cell-status-code";
export { DataTableCellLevelIndicator } from "./data-table-cell-level-indicator";

import { TextWithTooltip } from "@/components/custom/text-with-tooltip";

export function DataTableCellText({
  value,
  color,
}: {
  value: string | number;
  color?: string;
}) {
  return <TextWithTooltip text={value} style={color ? { color } : undefined} />;
}

export function DataTableCellCode({
  value,
  color,
}: {
  value: string | number;
  color?: string;
}) {
  return (
    <span className="font-mono" style={color ? { color } : undefined}>
      {value}
    </span>
  );
}

export function DataTableCellBadge({
  value,
  color,
}: {
  value: string | number;
  color?: string;
}) {
  return (
    <span
      className="rounded-sm border px-1.5 py-0.5 font-mono text-xs"
      style={
        color
          ? {
              color,
              backgroundColor: `${color}1a`,
              borderColor: `${color}33`,
            }
          : undefined
      }
    >
      {value}
    </span>
  );
}

import { Check, Minus } from "lucide-react";

export function DataTableCellBoolean({
  value,
  color,
}: {
  value: boolean;
  color?: string;
}) {
  if (value) {
    return (
      <Check
        className={`ml-auto h-4 w-4 ${color ? "" : "text-foreground"}`}
        style={color ? { color } : undefined}
      />
    );
  }
  return (
    <Minus
      className={`ml-auto h-4 w-4 ${color ? "" : "text-muted-foreground/50"}`}
      style={color ? { color } : undefined}
    />
  );
}

import { Star } from "lucide-react";

export function DataTableCellStar({ value }: { value: boolean }) {
  if (value) {
    return (
      <span className="ml-auto inline-flex items-center">
        <Star
          className="h-4 w-4 fill-yellow-400 text-yellow-400"
          aria-hidden="true"
        />
        <span className="sr-only">Favorited</span>
      </span>
    );
  }
  return (
    <span className="ml-auto inline-flex items-center">
      <Star className="text-muted-foreground/40 h-4 w-4" aria-hidden="true" />
      <span className="sr-only">Not favorited</span>
    </span>
  );
}

export function DataTableCellNumber({
  value,
  unit,
  color,
}: {
  value: number;
  unit?: string;
  color?: string;
}) {
  const formatted = new Intl.NumberFormat("en-US", {
    maximumFractionDigits: 3,
  }).format(value);

  return (
    <span className="font-mono" style={color ? { color } : undefined}>
      {formatted}
      {unit && <span className="text-muted-foreground">{unit}</span>}
    </span>
  );
}

import { getStatusColor } from "@/lib/request/status-code";

export function DataTableCellStatusCode({
  value,
  color,
}: {
  value: number;
  color?: string;
}) {
  const colors = getStatusColor(value);
  return (
    <span
      className={`font-mono ${color ? "" : colors.text}`}
      style={color ? { color } : undefined}
    >
      {value}
    </span>
  );
}

const LEVEL_COLORS: Record<string, string> = {
  error: "bg-red-500",
  warn: "bg-yellow-500",
  warning: "bg-yellow-500",
  info: "bg-blue-500",
  debug: "bg-gray-400",
  success: "bg-green-500",
};

export function DataTableCellLevelIndicator({
  value,
  color: colorOverride,
}: {
  value: string;
  color?: string;
}) {
  const builtinColor = LEVEL_COLORS[value.toLowerCase()] ?? "bg-gray-300";
  return (
    <span
      className="inline-flex items-center gap-1.5"
      style={colorOverride ? { color: colorOverride } : undefined}
    >
      <span
        className={`inline-block size-3.5 shrink-0 rounded-sm ${colorOverride ? "" : builtinColor}`}
        style={colorOverride ? { backgroundColor: colorOverride } : undefined}
      />
      <span>{value}</span>
    </span>
  );
}

"use client";

import { HoverCardTimestamp } from "@/components/data-table/data-table-infinite/hover-card-timestamp";

export function DataTableCellTimestamp({
  date,
  color,
}: {
  date: Date | string | number;
  color?: string;
}) {
  const d = date instanceof Date ? date : new Date(date);
  return (
    <span style={color ? { color } : undefined}>
      <HoverCardTimestamp date={d} />
    </span>
  );
}

import { hexToRgb } from "@/lib/colors";

const OPACITY = 0.1;

export function DataTableCellHeatmap({
  value,
  min,
  max,
  unit,
  color,
}: {
  value: number;
  min: number;
  max: number;
  unit?: string;
  color?: string;
}) {
  const range = max - min;
  const ratio =
    range === 0 ? 0 : Math.max(0, Math.min(1, (value - min) / range));
  const opacity = ratio * OPACITY;

  const formatted = new Intl.NumberFormat("en-US", {
    maximumFractionDigits: 3,
  }).format(value);

  return (
    <div className="relative -m-2 p-2">
      <div
        className="absolute inset-0"
        style={{
          backgroundColor: color
            ? `rgba(${hexToRgb(color)}, ${opacity})`
            : `var(--muted-foreground)`,
          opacity: color ? undefined : opacity,
        }}
      />
      <span className="relative font-mono">
        {formatted}
        {unit && <span className="text-muted-foreground">{unit}</span>}
      </span>
    </div>
  );
}

import { hexToRgb } from "@/lib/colors";

const OPACITY = 0.5;
const BORDER_OPACITY = 1;

export function DataTableCellBar({
  value,
  min,
  max,
  unit,
  color,
}: {
  value: number;
  min: number;
  max: number;
  unit?: string;
  color?: string;
}) {
  const range = max - min;
  const ratio =
    range === 0 ? 0 : Math.max(0, Math.min(1, (value - min) / range));

  const formatted = new Intl.NumberFormat("en-US", {
    maximumFractionDigits: 3,
  }).format(value);

  return (
    <div className="relative -m-2 p-2">
      <div
        className="absolute inset-y-0 left-0"
        style={{
          width: `${ratio * 100}%`,
          backgroundColor: color
            ? `rgba(${hexToRgb(color)}, ${OPACITY})`
            : `var(--muted)`,
          opacity: color ? undefined : OPACITY,
          borderRight: `1px solid ${color ? `rgba(${hexToRgb(color)}, ${BORDER_OPACITY})` : `var(--border)`}`,
        }}
      />
      <span className="relative font-mono">
        {formatted}
        {unit && <span className="text-muted-foreground">{unit}</span>}
      </span>
    </div>
  );
}

import { hexToRgb } from "@/lib/colors";

const BG_OPACITY = 0.2;
const FOREGROUND_OPACITY = 0.5;

export function DataTableCellGauge({
  value,
  min,
  max,
  unit,
  color,
}: {
  value: number;
  min: number;
  max: number;
  unit?: string;
  color?: string;
}) {
  const range = max - min;
  const ratio =
    range === 0 ? 0 : Math.max(0, Math.min(1, (value - min) / range));

  // SVG circle gauge calculations
  const size = 20;
  const strokeWidth = 4;
  const viewBox = 120;
  const radius = 50;
  const circumference = 2 * Math.PI * radius;
  const strokeDashoffset = circumference - ratio * circumference;

  const bgStroke = color
    ? `rgba(${hexToRgb(color)}, ${BG_OPACITY})`
    : `var(--muted)`;

  const fgStroke = color
    ? `rgba(${hexToRgb(color)}, ${FOREGROUND_OPACITY})`
    : `var(--muted-foreground)`;

  const formatted = new Intl.NumberFormat("en-US", {
    maximumFractionDigits: 3,
  }).format(value);

  return (
    <div className="flex items-center gap-1.5">
      <svg
        fill="none"
        height={size}
        width={size}
        viewBox={`0 0 ${viewBox} ${viewBox}`}
        className="shrink-0 -rotate-90"
      >
        <circle
          strokeWidth={strokeWidth * 4}
          stroke={bgStroke}
          fill="transparent"
          r={radius}
          cx={viewBox / 2}
          cy={viewBox / 2}
        />
        <circle
          strokeWidth={strokeWidth * 4}
          strokeDasharray={`${circumference} ${circumference}`}
          strokeDashoffset={strokeDashoffset}
          strokeLinecap="round"
          stroke={fgStroke}
          fill="transparent"
          r={radius}
          cx={viewBox / 2}
          cy={viewBox / 2}
        />
      </svg>
      <span className="font-mono">
        {formatted}
        {unit && <span className="text-muted-foreground">{unit}</span>}
      </span>
    </div>
  );
}

export function hexToRgb(hex: string): string {
  const normalizedHex = hex.trim().replace(/^#/, "");

  let rgbHex: string;

  if (/^[0-9a-fA-F]{3}$/.test(normalizedHex)) {
    rgbHex = normalizedHex
      .split("")
      .map((char) => char + char)
      .join("");
  } else if (/^[0-9a-fA-F]{6}$/.test(normalizedHex)) {
    rgbHex = normalizedHex;
  } else if (/^[0-9a-fA-F]{8}$/.test(normalizedHex)) {
    rgbHex = normalizedHex.substring(0, 6);
  } else {
    return "0, 0, 0";
  }

  const r = parseInt(rgbHex.substring(0, 2), 16);
  const g = parseInt(rgbHex.substring(2, 4), 16);
  const b = parseInt(rgbHex.substring(4, 6), 16);

  if (Number.isNaN(r) || Number.isNaN(g) || Number.isNaN(b)) {
    return "0, 0, 0";
  }

  return `${r}, ${g}, ${b}`;
}

import {
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
} from "@/components/ui/tooltip";
import { cn } from "@/lib/utils";
import React, { useEffect, useRef, useState } from "react";

interface TextWithTooltipProps {
  text: string | number;
  className?: string;
  style?: React.CSSProperties;
}

export function TextWithTooltip({
  text,
  className,
  style,
}: TextWithTooltipProps) {
  const [isTruncated, setIsTruncated] = useState<boolean>(false);
  const textRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const checkTruncation = () => {
      if (textRef.current) {
        const { scrollWidth, clientWidth } = textRef.current;
        setIsTruncated(scrollWidth > clientWidth);
      }
    };

    const resizeObserver = new ResizeObserver(() => {
      checkTruncation();
    });

    if (textRef.current) {
      resizeObserver.observe(textRef.current);
    }

    checkTruncation();

    return () => {
      resizeObserver.disconnect();
    };
  }, []);

  return (
    <TooltipProvider delayDuration={100} disableHoverableContent>
      <Tooltip>
        <TooltipTrigger disabled={!isTruncated} asChild>
          <div
            ref={textRef}
            className={cn(
              "truncate",
              !isTruncated && "pointer-events-none",
              className,
            )}
            style={style}
          >
            {text}
          </div>
        </TooltipTrigger>
        <TooltipContent>{text}</TooltipContent>
      </Tooltip>
    </TooltipProvider>
  );
}

"use client";

import {
  HoverCard,
  HoverCardContent,
  HoverCardTrigger,
} from "@/components/ui/hover-card";
import { useCopyToClipboard } from "@/hooks/use-copy-to-clipboard";
import { cn } from "@/lib/utils";
import { UTCDate } from "@date-fns/utc";
import { format, formatDistanceToNowStrict } from "date-fns";
import { Check, Copy } from "lucide-react";
import type { ComponentPropsWithoutRef } from "react";

type HoverCardContentProps = ComponentPropsWithoutRef<typeof HoverCardContent>;

interface HoverCardTimestampProps {
  date: Date;
  side?: HoverCardContentProps["side"];
  sideOffset?: HoverCardContentProps["sideOffset"];
  align?: HoverCardContentProps["align"];
  alignOffset?: HoverCardContentProps["alignOffset"];
  className?: string;
}

export function HoverCardTimestamp({
  date,
  side = "right",
  align = "start",
  alignOffset = -4,
  sideOffset,
  className,
}: HoverCardTimestampProps) {
  const timezone = Intl.DateTimeFormat().resolvedOptions().timeZone;

  return (
    <HoverCard openDelay={0} closeDelay={0}>
      <HoverCardTrigger asChild>
        <div className={cn("font-mono whitespace-nowrap", className)}>
          {format(date, "LLL dd, y HH:mm:ss")}
        </div>
      </HoverCardTrigger>
      {/* Portal is built into HoverCardContent in shadcn v4 */}
      <HoverCardContent
        className="z-10 w-auto p-2"
        {...{ side, align, alignOffset, sideOffset }}
      >
        <dl className="flex flex-col gap-1">
          <Row value={String(date.getTime())} label="Timestamp" />
          <Row
            value={format(new UTCDate(date), "LLL dd, y HH:mm:ss")}
            label="UTC"
          />
          <Row value={format(date, "LLL dd, y HH:mm:ss")} label={timezone} />
          <Row
            value={formatDistanceToNowStrict(date, { addSuffix: true })}
            label="Relative"
          />
        </dl>
      </HoverCardContent>
    </HoverCard>
  );
}

function Row({ value, label }: { value: string; label: string }) {
  const { copy, isCopied } = useCopyToClipboard();

  return (
    <div
      className="group flex items-center justify-between gap-4 text-sm"
      onClick={(e) => {
        e.stopPropagation();
        copy(value);
      }}
    >
      <dt className="text-muted-foreground">{label}</dt>
      <dd className="flex items-center gap-1 truncate font-mono">
        <span className="invisible group-hover:visible">
          {!isCopied ? (
            <Copy className="h-3 w-3" />
          ) : (
            <Check className="h-3 w-3" />
          )}
        </span>
        {value}
      </dd>
    </div>
  );
}

"use client";

import { useCallback, useState } from "react";
import { toast } from "sonner";

export function useCopyToClipboard() {
  const [text, setText] = useState<string | null>(null);

  const copy = useCallback(
    async (
      text: string,
      { timeout, withToast }: { timeout?: number; withToast?: boolean } = {
        timeout: 3000,
        withToast: false,
      },
    ) => {
      if (!navigator?.clipboard) {
        console.warn("Clipboard not supported");
        return false;
      }

      try {
        await navigator.clipboard.writeText(text);
        setText(text);

        if (timeout) {
          setTimeout(() => {
            setText(null);
          }, timeout);
        }

        if (withToast) {
          toast.success("Copied to clipboard");
        }

        return true;
      } catch (error) {
        console.warn("Copy failed", error);
        setText(null);
        return false;
      }
    },
    [],
  );

  return { text, copy, isCopied: text !== null };
}
